-- Step 1: Close all open positions (mark as force-closed)
UPDATE paper_positions SET status = 'closed', closed_at = NOW(), exit_reason = 'RESET_LAB_BUG_C1', realized_pnl = 0 WHERE status = 'open';

-- Step 2: Reset ledger to $100k initial capital for all users
UPDATE paper_ledger SET available_cash = 100000, updated_at = NOW();

-- Step 3: Verify
SELECT COUNT(*) as open_positions FROM paper_positions WHERE status = 'open';
SELECT available_cash, initial_capital FROM paper_ledger LIMIT 5;

